2025	\section{Properness}
2026	\label{sec:gr_proper}
2027	
2028	Following Nitsure \S 1, the structure morphism \(\pi : \mathrm{Gr}(r,d) \to \Spec
2029	\mathbb{Z}\) is proper. We reduce properness to the \emph{existence} half of the
2030	valuative criterion: the Mathlib criterion \texttt{IsProper.of\_valuativeCriterion}
2031	reduces \(\mathrm{IsProper}\,\pi\) to four ingredients --- quasi-compactness,
2032	quasi-separatedness, local finiteness of type, and the valuative criterion
2033	\(\mathrm{Existence} \sqcap \mathrm{Uniqueness}\). The first three and the
2034	uniqueness half are cheap (uniqueness is free from separatedness), so the only
2035	genuine content is \(\mathrm{Existence}\): every commutative square from a
2036	valuation ring admits a diagonal filler. This existence statement is the Nitsure
2037	chart-selection argument, which we decompose into four steps E1--E4.
2038	
2039	\subsection*{Cheap ingredients and the reduction to existence}
2040	
2041	\begin{lemma}
2042	[\(\mathrm{Gr}(r,d)\) is a compact space]
2043	  \label{lem:gr_compactSpace_scheme}
2044	  \lean{AlgebraicGeometry.Grassmannian.compactSpace_scheme}
2045	  \uses{def:gr_the_glue_data, def:gr_affine_chart, def:gr_glued_scheme}
2046	  The underlying topological space of the glued Grassmannian scheme
2047	  \(\mathrm{Gr}(r,d)\) (\cref{def:gr_glued_scheme}) is quasi-compact: it carries the
2048	  structure of a \texttt{CompactSpace}.
2049	\end{lemma}
2050	\begin{proof}
2051	  \uses{def:gr_the_glue_data, def:gr_affine_chart}
2052	  The glue datum (\cref{def:gr_the_glue_data}) is indexed by the finite set
2053	  \(\{\, I \subseteq \{1,\dots,r\} : \#(I) = d \,\}\) of size-\(d\) subsets, and
2054	  each chart \(U^I = \Spec \mathbb{Z}[X^I]\) (\cref{def:gr_affine_chart}) is the
2055	  \(\Spec\) of a ring, hence quasi-compact. A scheme glued from finitely many
2056	  quasi-compact charts is quasi-compact, so \(\mathrm{Gr}(r,d)\) is a compact
2057	  space.
2058	\end{proof}
2059	
2060	\begin{lemma}
2061	[The structure morphism is quasi-compact]
2062	  \label{lem:gr_quasiCompact_toSpecZ}
2063	  \lean{AlgebraicGeometry.Grassmannian.quasiCompact_toSpecZ}
2064	  \uses{def:gr_to_specZ, lem:gr_compactSpace_scheme}
2065	  The structure morphism \(\pi : \mathrm{Gr}(r,d) \to \Spec \mathbb{Z}\)
2066	  (\cref{def:gr_to_specZ}) is quasi-compact.
2067	\end{lemma}
2068	\begin{proof}
2069	  \uses{lem:gr_compactSpace_scheme}
2070	  The target \(\Spec \mathbb{Z}\) is affine, so quasi-compactness of \(\pi\) is
2071	  equivalent to quasi-compactness of the total space \(\mathrm{Gr}(r,d)\), which is
2072	  a compact space by \cref{lem:gr_compactSpace_scheme}.
2073	\end{proof}
2074	
2075	\begin{lemma}
2076	[The structure morphism is locally of finite type]
2077	  \label{lem:gr_locallyOfFiniteType_toSpecZ}
2078	  \lean{AlgebraicGeometry.Grassmannian.locallyOfFiniteType_toSpecZ}
2079	  \uses{def:gr_to_specZ, def:gr_the_glue_data, def:gr_affine_chart, lem:gr_ι_toSpecZ}
2080	  The structure morphism \(\pi : \mathrm{Gr}(r,d) \to \Spec \mathbb{Z}\)
2081	  (\cref{def:gr_to_specZ}) is locally of finite type.
2082	\end{lemma}
2083	\begin{proof}
2084	  \uses{def:gr_the_glue_data, lem:gr_ι_toSpecZ}
2085	  Being locally of finite type is local on the source, so it may be checked on the
2086	  chart open cover (\cref{def:gr_the_glue_data}). On the chart \(U^I\) the composite
2087	  \(U^I \to \mathrm{Gr}(r,d) \xrightarrow{\pi} \Spec \mathbb{Z}\) is, by
2088	  \cref{lem:gr_ι_toSpecZ}, the \(\Spec\) of the structure map \(\mathbb{Z} \to R^I
2089	  = \mathbb{Z}[X^I]\). The polynomial ring \(\mathbb{Z}[X^I]\) is a finitely
2090	  generated \(\mathbb{Z}\)-algebra, so this map is of finite type; hence \(\pi\) is
2091	  locally of finite type.
2092	\end{proof}
