2094	\begin{lemma}
2095	[The structure morphism is quasi-separated]
2096	  \label{lem:gr_quasiSeparated_toSpecZ}
2097	  \lean{AlgebraicGeometry.Grassmannian.quasiSeparated_toSpecZ}
2098	  \uses{def:gr_to_specZ, lem:gr_separated_toSpecZ}
2099	  The structure morphism \(\pi : \mathrm{Gr}(r,d) \to \Spec \mathbb{Z}\)
2100	  (\cref{def:gr_to_specZ}) is quasi-separated.
2101	\end{lemma}
2102	\begin{proof}
2103	  \uses{lem:gr_separated_toSpecZ}
2104	  The structure morphism is separated (\cref{lem:gr_separated_toSpecZ}), and every
2105	  separated morphism is quasi-separated.
2106	\end{proof}
2107	
2108	\begin{lemma}
2109	[Uniqueness half of the valuative criterion]
2110	  \label{lem:gr_valuativeUniqueness_toSpecZ}
2111	  \lean{AlgebraicGeometry.Grassmannian.valuativeUniqueness_toSpecZ}
2112	  \uses{def:gr_to_specZ, lem:gr_separated_toSpecZ}
2113	  The structure morphism \(\pi : \mathrm{Gr}(r,d) \to \Spec \mathbb{Z}\)
2114	  (\cref{def:gr_to_specZ}) satisfies the \emph{uniqueness} part of the valuative
2115	  criterion: for a valuation ring \(R\) with fraction field \(K\), any two
2116	  morphisms \(\Spec R \to \mathrm{Gr}(r,d)\) over \(\Spec \mathbb{Z}\) that agree
2117	  on the generic point \(\Spec K\) coincide.
2118	\end{lemma}
2119	\begin{proof}
2120	  \uses{lem:gr_separated_toSpecZ}
2121	  The structure morphism is separated (\cref{lem:gr_separated_toSpecZ}), and the
2122	  uniqueness half of the valuative criterion is free for any separated morphism:
2123	  two lifts agreeing on the schematically dense generic point of \(\Spec R\)
2124	  coincide because the diagonal is a (closed, in particular separated) immersion.
2125	\end{proof}
