2127	\begin{lemma}
2128	[Properness from the existence half of the valuative criterion]
2129	  \label{lem:gr_isProper_of_valuativeExistence}
2130	  \lean{AlgebraicGeometry.Grassmannian.isProper_of_valuativeExistence}
2131	  \uses{lem:gr_compactSpace_scheme, lem:gr_quasiCompact_toSpecZ,
2132	    lem:gr_locallyOfFiniteType_toSpecZ, lem:gr_quasiSeparated_toSpecZ,
2133	    lem:gr_valuativeUniqueness_toSpecZ, def:gr_to_specZ}
2134	  Suppose the structure morphism \(\pi : \mathrm{Gr}(r,d) \to \Spec \mathbb{Z}\)
2135	  (\cref{def:gr_to_specZ}) satisfies the \emph{existence} part of the valuative
2136	  criterion. Then \(\pi\) is proper.
2137	\end{lemma}
2138	\begin{proof}
2139	  \uses{lem:gr_quasiCompact_toSpecZ, lem:gr_locallyOfFiniteType_toSpecZ,
2140	    lem:gr_quasiSeparated_toSpecZ, lem:gr_valuativeUniqueness_toSpecZ}
2141	  The Mathlib criterion \texttt{IsProper.of\_valuativeCriterion} reduces properness
2142	  of \(\pi\) to four hypotheses: \(\pi\) is quasi-compact
2143	  (\cref{lem:gr_quasiCompact_toSpecZ}), quasi-separated
2144	  (\cref{lem:gr_quasiSeparated_toSpecZ}), locally of finite type
2145	  (\cref{lem:gr_locallyOfFiniteType_toSpecZ}), and satisfies the full valuative
2146	  criterion. The full valuative criterion is the conjunction of its existence and
2147	  uniqueness halves; the uniqueness half holds by
2148	  \cref{lem:gr_valuativeUniqueness_toSpecZ}, and the existence half is the
2149	  hypothesis. Assembling the four ingredients gives properness.
2150	\end{proof}
